/// Service: dd-remote-rest-api
pub const THREAD_CONTROL_PATTERN: &str = "dd.remote.thread.{thread_id}.control";
pub const THREAD_CONTROL_WILDCARD: &str = "dd.remote.thread.*.control";
pub const THREAD_CONTROL_STREAM: &str = "DD_REMOTE_CONTROL";
pub fn thread_control_subject(thread_id: &str) -> String {
    format!("dd.remote.thread.{}.control", thread_id)
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ThreadControlSubjectParts {
    pub thread_id: String,
}

pub fn parse_thread_control_subject(subject: &str) -> Option<ThreadControlSubjectParts> {
    let pattern_tokens: &[&str] = &["dd", "remote", "thread", "{thread_id}", "control"];
    let subject_tokens: Vec<&str> = subject.split('.').collect();
    let mut thread_id: Option<String> = None;
    let mut si: usize = 0;
    for tok in pattern_tokens.iter() {
        if tok.starts_with('{') && tok.ends_with('}') {
            if si >= subject_tokens.len() { return None; }
            let name = &tok[1..tok.len()-1];
            match name {
                "thread_id" => { thread_id = Some(subject_tokens[si].to_string()); }
                _ => return None,
            }
            si += 1;
            continue;
        }
        if si >= subject_tokens.len() || subject_tokens[si] != *tok { return None; }
        si += 1;
    }
    if si != subject_tokens.len() { return None; }
    Some(ThreadControlSubjectParts {
        thread_id: thread_id?,
    })
}

